<script setup lang="ts">
import { computed, onMounted, ref, watch } from 'vue'
import { openTheBestSearch } from '@/components/TheBestSearch/open'


const props = withDefaults(defineProps<{
    breadcrumbs?: string[]
    currentFunctionLabel?: string
    leftCollapsed?: boolean
    rightCollapsed?: boolean
    theme?: 'light' | 'dark'
    isMobileNewrooms?: boolean
}>(), {
    breadcrumbs: () => [],
    currentFunctionLabel: '功能导航',
    leftCollapsed: false,
    rightCollapsed: false,
    theme: 'light'
})

const emit = defineEmits<{
    (event: 'toggle-left'): void
    (event: 'toggle-right'): void
    (event: 'set-theme', value: 'light' | 'dark'): void
    (event: 'open-settings'): void
    (event: 'open-feedback'): void
}>()

const currentTheme = ref(props.theme)
const leftCollapsed = computed(() => props.leftCollapsed)
const rightCollapsed = computed(() => props.rightCollapsed)
const breadcrumbs = computed(() => props.breadcrumbs)
const currentFunctionLabel = computed(() => props.currentFunctionLabel)

const updateTheme = (
    value: 'light' | 'dark',
    options: { emitEvent?: boolean; persist?: boolean } = {}
) => {
    const { emitEvent = true, persist = true } = options
    currentTheme.value = value
    if (typeof document !== 'undefined') {
        document.documentElement.setAttribute('data-theme', value)
    }
    if (persist && typeof window !== 'undefined') {
        try {
            window.localStorage.setItem('theme', value)
        } catch (error) {
            console.warn('[NewRightContentHead] 无法持久化主题设置:', error)
        }
    }
    if (emitEvent) {
        emit('set-theme', value)
    }
}

// 搜索按钮直接在模板中调用 openTheBestSearch，全局统一入口，不再通过 search 事件中转

const handleThemeClick = (value: 'light' | 'dark') => {
    updateTheme(value)
}

onMounted(() => {
    if (typeof window === 'undefined') return
    const storedTheme = window.localStorage.getItem('theme') === 'dark' ? 'dark' : 'light'
    updateTheme(storedTheme, { emitEvent: false, persist: false })
})

watch(
    () => props.theme,
    (value) => {
        if (!value) return
        updateTheme(value, { emitEvent: false })
    }
)
</script>

